public <WO extends OrderedMonoid<W>> WeightedPath<V, WE, W> applyingDijkstra(
        WO weightOperations) {
    weightOperations =
            checkNotNull(
                    weightOperations,
                    "Dijkstra algorithm can not be applied using null weight operations");

    final ShortestDistances<V, W> shortestDistances =
            new ShortestDistances<V, W>(weightOperations);
    shortestDistances.setWeight(source, weightOperations.identity());

    final Queue<V> unsettledNodes = new FibonacciHeap<V>(shortestDistances);
    unsettledNodes.add(source);

    final Set<V> settledNodes = new HashSet<V>();

    final PredecessorsList<V, WE, W> predecessors =
            new PredecessorsList<V, WE, W>(graph, weightOperations, weightedEdges);

    while (!unsettledNodes.isEmpty()) {
        V vertex = unsettledNodes.remove();

        if (target.equals(vertex)) {
            return predecessors.buildPath0(source, target);
        }

        settledNodes.add(vertex);

        for (V v : graph.getConnectedVertices(vertex)) {
            if (!settledNodes.contains(v)) {
                WE edge = graph.getEdge(vertex, v);
                if (shortestDistances.alreadyVisited(vertex)) {
                    W shortDist =
                            weightOperations.append(
                                    shortestDistances.getWeight(vertex),
                                    weightedEdges.map(edge));

                    if (!shortestDistances.alreadyVisited(v)
                            || weightOperations.compare(
                                            shortDist, shortestDistances.getWeight(v))
                                    < 0) {
                        shortestDistances.setWeight(v, shortDist);
                        unsettledNodes.add(v);

                        predecessors.addPredecessor(v, vertex);
                    }
                }
            }
        }
    }

    throw new PathNotFoundException(
            "Path from '%s' to '%s' doesn't exist in Graph '%s'", source, target, graph);
}

public <WO extends OrderedMonoid<W>> WeightedPath<V, WE, W> applyingBidirectionalDijkstra(
        WO weightOperations) {
    weightOperations =
            checkNotNull(
                    weightOperations,
                    "Bidirectional Dijkstra algorithm can not be applied using null weight"
                            + " operations");

    final ShortestDistances<V, W> shortestDistancesForward =
            new ShortestDistances<V, W>(weightOperations);
    shortestDistancesForward.setWeight(source, weightOperations.identity());

    final ShortestDistances<V, W> shortestDistancesBackwards =
            new ShortestDistances<V, W>(weightOperations);
    shortestDistancesBackwards.setWeight(target, weightOperations.identity());

    final Queue<V> openForward = new FibonacciHeap<V>(shortestDistancesForward);
    openForward.add(source);

    final Queue<V> openBackwards = new FibonacciHeap<V>(shortestDistancesBackwards);
    openBackwards.add(target);

    final Set<V> closedForward = new HashSet<V>();

    final Set<V> closedBackwards = new HashSet<V>();

    final PredecessorsList<V, WE, W> predecessorsForward =
            new PredecessorsList<V, WE, W>(graph, weightOperations, weightedEdges);

    final PredecessorsList<V, WE, W> predecessorsBackwards =
            new PredecessorsList<V, WE, W>(graph, weightOperations, weightedEdges);

    W best = null;
    V touch = null;

    while (!openForward.isEmpty() && !openBackwards.isEmpty()) {
        if (best != null) {
            final W tmp =
                    weightOperations.append(
                            shortestDistancesForward.getWeight(openForward.peek()),
                            shortestDistancesBackwards.getWeight(openBackwards.peek()));

            if (weightOperations.compare(tmp, best) >= 0) {
                return predecessorsForward.buildPath1(
                        source, touch, target, predecessorsBackwards);
            }
        }

        V vertex = openForward.remove();

        closedForward.add(vertex);

        for (V v : graph.getConnectedVertices(vertex)) {
            if (!closedForward.contains(v)) {
                WE edge = graph.getEdge(vertex, v);
                if (shortestDistancesForward.alreadyVisited(vertex)) {
                    W shortDist =
                            weightOperations.append(
                                    shortestDistancesForward.getWeight(vertex),
                                    weightedEdges.map(edge));

                    if (!shortestDistancesForward.alreadyVisited(v)
                            || weightOperations.compare(
                                            shortDist, shortestDistancesForward.getWeight(v))
                                    < 0) {
                        shortestDistancesForward.setWeight(v, shortDist);
                        openForward.add(v);
                        predecessorsForward.addPredecessor(v, vertex);

                        if (closedBackwards.contains(v)) {
                            W tmpBest =
                                    weightOperations.append(
                                            shortDist, shortestDistancesBackwards.getWeight(v));

                            if (best == null || weightOperations.compare(tmpBest, best) < 0) {
                                best = tmpBest;
                                touch = v;
                            }
                        }
                    }
                }
            }
        }

        vertex = openBackwards.remove();

        closedBackwards.add(vertex);

        Iterable<V> parentsIterable =
                (graph instanceof DirectedGraph
                        ? ((DirectedGraph<V, WE>) graph).getInbound(vertex)
                        : graph.getConnectedVertices(vertex));

        for (V v : parentsIterable) {
            if (!closedBackwards.contains(v)) {
                WE edge = graph.getEdge(v, vertex);
                if (shortestDistancesBackwards.alreadyVisited(vertex)) {
                    W shortDist =
                            weightOperations.append(
                                    shortestDistancesBackwards.getWeight(vertex),
                                    weightedEdges.map(edge));

                    if (!shortestDistancesBackwards.alreadyVisited(v)
                            || weightOperations.compare(
                                            shortDist, shortestDistancesBackwards.getWeight(v))
                                    < 0) {
                        shortestDistancesBackwards.setWeight(v, shortDist);
                        openBackwards.add(v);
                        predecessorsBackwards.addPredecessor(v, vertex);

                        if (closedForward.contains(v)) {
                            W tmpBest =
                                    weightOperations.append(
                                            shortDist, shortestDistancesForward.getWeight(v));

                            if (best == null || weightOperations.compare(tmpBest, best) < 0) {
                                best = tmpBest;
                                touch = v;
                            }
                        }
                    }
                }
            }
        }
    }

    if (touch == null) {
        throw new PathNotFoundException(
                "Path from '%s' to '%s' doesn't exist in Graph '%s'", source, target, graph);
    }

    return predecessorsForward.buildPath1(source, touch, target, predecessorsBackwards);
}

public <WO extends OrderedMonoid<W>> HeuristicBuilder<V, WE, W> applyingAStar(
        WO weightOperations) {
    weightOperations =
            checkNotNull(
                    weightOperations,
                    "A* algorithm can not be applied using null weight operations");
    return new DefaultHeuristicBuilder<V, WE, W>(
            graph, weightedEdges, source, target, weightOperations);
}

public DefaultShortestPathAlgorithmSelector(
        Graph<V, WE> graph, Mapper<WE, W> weightedEdges, V source, V target) {
    this.graph = graph;
    this.weightedEdges = weightedEdges;
    this.source = source;
    this.target = target;
}
